<template><Head :title="`Edit ${car.title}`" /><DealerLayout title="Edit Car" eyebrow="Inventory"><section class="mb-5 flex flex-col gap-3 rounded-lg border border-slate-200 bg-white p-5 shadow-sm sm:flex-row sm:items-center sm:justify-between"><div><Status :value="car.status" /><h2 class="mt-2 text-2xl font-black text-slate-950">{{ car.title }}</h2><p v-if="car.rejection_reason" class="mt-2 text-sm font-bold text-red-600">{{ car.rejection_reason }}</p></div></section><CarForm :initial="car" :brands="brands" :fuel-types="fuelTypes" :transmissions="transmissions" :action="actions.update" :cancel-url="actions.index" is-edit /><section v-if="car.images.length" class="mt-5 rounded-lg border border-slate-200 bg-white p-5 shadow-sm"><h3 class="text-xl font-black text-slate-950">Current images</h3><div class="mt-4 grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-5"><div v-for="image in car.images" :key="image.id" class="rounded-lg border border-slate-200 p-2"><img :src="image.url" alt="" class="aspect-[4/3] w-full rounded-md object-cover" /><span v-if="image.is_primary" class="mt-2 inline-flex rounded-md bg-teal-50 px-2 py-1 text-xs font-black text-teal-700">Primary</span><div class="mt-2 flex gap-2"><button type="button" class="flex-1 rounded-md border border-slate-200 px-2 py-1.5 text-xs font-black text-slate-700 disabled:opacity-40" :disabled="image.is_primary" @click="primary(image)">Primary</button><button type="button" class="rounded-md border border-red-200 px-2 py-1.5 text-xs font-black text-red-700" @click="remove(image)">Delete</button></div></div></div></section></DealerLayout></template>
<script setup lang="ts">import{defineComponent,h}from'vue';import{Head,router}from'@inertiajs/vue3';import DealerLayout from '@/Layouts/DealerLayout.vue';import CarForm from './Partials/CarForm.vue';type Image={id:number;url:string;is_primary:boolean;actions:{primary:string;delete:string}};const props=defineProps<{car:any;brands:Array<{id:number;name:string}>;fuelTypes:Array<{value:string;label:string}>;transmissions:Array<{value:string;label:string}>;actions:{update:string;index:string}}>();const primary=(image:Image)=>router.post(image.actions.primary,{}, {preserveScroll:true});const remove=(image:Image)=>{if(window.confirm('Delete this image?'))router.delete(image.actions.delete,{preserveScroll:true});};const Status=defineComponent({props:{value:{type:String,required:true}},setup(p){return()=>h('span',{class:['inline-flex rounded-md px-2.5 py-1 text-xs font-black capitalize',p.value==='approved'?'bg-teal-50 text-teal-700':p.value==='pending'?'bg-orange-50 text-orange-700':'bg-red-50 text-red-700']},p.value);}});</script>
